#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long N, M, L;
        scanf("%llu %llu %llu", &N, &M, &L);
        unsigned long long rem = M;
        for (unsigned long long i = N; i >= 1; --i) {
            unsigned long long buckets = L + i - 1ULL;
            rem %= buckets;
            if (i == 1) break; // avoid underflow of unsigned i
        }
        printf("%llu\n", rem);
    }
    return 0;
}

